mapper.update:
UPDATE ai_capability_invocation_log
SET result_status = #{log.resultStatus},
    result_code = #{log.resultCode},
    error_code = #{log.errorCode},
    schema_path = #{log.schemaPath},
    trace_id = #{log.traceId},
    duration_ms = #{log.durationMs},
    update_by = COALESCE(#{log.updateBy}, update_by),
    update_time = COALESCE(#{log.updateTime}, NOW())
WHERE tenant_id = #{log.tenantId}
  AND request_id = #{log.requestId}
  AND client_id = #{log.clientId}
  AND client_code = #{log.clientCode}
  AND capability_id = #{log.capabilityId}
  AND capability_code = #{log.capabilityCode}
  AND actor_type = #{log.actorType}
  AND actor_user_id = #{log.actorUserId}
  AND service_user_id = #{log.serviceUserId}
  AND active_org_id = #{log.activeOrgId}
  AND del_flag = 0

mapper.select:
SELECT  FROM ai_capability_invocation_log
WHERE tenant_id = #{tenantId} AND del_flag = 0
AND client_id = #{clientId}
AND capability_code = #{capabilityCode}
AND result_code = #{resultCode}
ORDER BY create_time DESC, id DESC
